// Decode an uplink message from a buffer
// payload - array of bytes
// metadata - key/value object

/** Decoder **/

// decode payload to string
//var payloadStr = decodeToString(payload);

// decode payload to JSON
var data = decodeToJson(payload);

var deviceName = 'Armando_AI';
var deviceType = 'Armando AI';
var risposta = data.response;
var t=lzw_decode(data.grafo);
//var grafo = JSON.parse(pako.inflate(compressed, { to: 'string' }));
function lzw_decode(compressedStr) {
    // Controllo di sicurezza esplicito per TBEL
    if (compressedStr == null) { return ""; }
    if (compressedStr.length() == 0) { return ""; }

    var dict = {};
    var currChar = "" + compressedStr.charAt(0);
    var oldPhrase = currChar;
    var out = [];
    out.push(currChar);
    var code = 256;
    var phrase = "";

    // Usiamo .length() con le parentesi (stile Java)
    for (var i = 1; i < compressedStr.length(); i++) {
        var c = compressedStr.charAt(i);
        // Otteniamo il codice numerico in modo sicuro per TBEL
        var currCode = c.hashCode(); 

        if (currCode < 256) {
            phrase = "" + c;
        } else {
            if (dict[currCode] != null) {
                phrase = dict[currCode];
            } else {
                phrase = oldPhrase + currChar;
            }
        }

        out.push(phrase);
        currChar = "" + phrase.charAt(0);
        dict[code] = oldPhrase + currChar;
        code++;
        oldPhrase = phrase;
    }

    // Uniamo l'array in una stringa finale
    var result = "";
    for (var j = 0; j < out.length; j++) {
        result += out[j];
    }
    return result;
}
// Result object with device/asset attributes/telemetry data
var result = {
// Use deviceName and deviceType or assetName and assetType, but not both.
   deviceName: deviceName,
   deviceType: deviceType,
// assetName: assetName,
// assetType: assetType,
// customerName: customerName,
   attributes: {
       grafo : t,
       risposta: risposta
   },
   telemetry: {
       chat: risposta
   }
};

/** Helper functions 'decodeToString' and 'decodeToJson' are already built-in **/

return result;
